const lines = csv.split(/\r?\n/)

lines.forEach((rawLine) => {
  const line = rawLine.trim()
  if (!line) return
  if (line.startsWith('#')) return // allow comments

  // Simple CSV-like split that supports quoted fields
  const rawBlocks = line.match(/(".*?"|[^",\s]+)(?=\s*,|\s*$)/g) || []
  const blocks = rawBlocks.map(s => s.replace(/^"|"$/g, '').trim()).filter(Boolean)
  if (blocks.length === 0) return

  const inputBlock = blocks[0]
  if (!inputBlock) return

  // Use Set to deduplicate outputs and ignore empty entries
  const uniqueOutputs = Array.from(new Set(blocks.slice(1)))
  uniqueOutputs.forEach(output => {
    if (output) event.stonecutting(output, inputBlock)
  })
})
